SELECT * FROM INQUIRY WHERE IS_DELETED = 'N'
AND STATUS = #{status}
AND CATEGORY = #{category}
AND TITLE LIKE '%' || #{keyword} || '%'
AND MEMBER_NO = TO_NUMBER(#{keyword})
ORDER BY NO DESC OFFSET #{offset} ROWS FETCH NEXT #{size} ROWS ONLY

SELECT COUNT(*) FROM INQUIRY WHERE IS_DELETED = 'N'
AND STATUS = #{status}
AND CATEGORY = #{category}
AND TITLE LIKE '%' || #{keyword} || '%'
AND MEMBER_NO = TO_NUMBER(#{keyword})

SELECT *
FROM INQUIRY
WHERE NO = #{no}
AND MEMBER_NO = #{memberNo}
AND IS_DELETED = 'N'
